def get_table_name(base_name):
    """Generate consistent DynamoDB table name following naming convention."""
    return f"{PROJECT}-{ENV}-{base_name}"


def get_bucket_name(base_name):
    """Generate consistent S3 bucket name following naming convention."""
    return f"{PROJECT}-{ENV}-{base_name}"


def get_topic_arn(topic_name):
    """Generate consistent SNS topic ARN."""
    account_id = boto3.client('sts').get_caller_identity()['Account']
    return f"arn:aws:sns:{REGION}:{account_id}:{PROJECT}-{ENV}-{topic_name}"


def get_queue_url(queue_name):
    """Get SQS queue URL by naming convention."""
    full_name = f"{PROJECT}-{ENV}-{queue_name}"
    response = get_sqs_client().get_queue_url(QueueName=full_name)
    return response['QueueUrl']


class ServiceResponse:
    """Standardized response builder for all microservice Lambda functions."""

    @staticmethod
    def success(body, status_code=200):
        return {
            'statusCode': status_code,
            'headers': {
                'Content-Type': 'application/json',
                'X-Service-Environment': ENV,
                'X-Service-Project': PROJECT,
            },
            'body': json.dumps({
                'success': True,
                'data': body,
                'metadata': {
                    'environment': ENV,
                    'timestamp': datetime.utcnow().isoformat() + 'Z',
                }
            })
        }

    @staticmethod
    def error(message, status_code=500, error_code=None):
        return {
            'statusCode': status_code,
            'headers': {
                'Content-Type': 'application/json',
                'X-Service-Environment': ENV,
                'X-Service-Project': PROJECT,
            },
            'body': json.dumps({
                'success': False,
                'error': {
                    'message': message,
                    'code': error_code or f'ERR_{status_code}',
                },
                'metadata': {
                    'environment': ENV,
                    'timestamp': datetime.utcnow().isoformat() + 'Z',
                }
            })
        }


class MicroserviceBase:
    """
    Base class providing common operations for all microservice Lambda functions.
    All 10+ Lambda functions inherit from this to use shared IAM role permissions.
    """

    def __init__(self, service_name):
        self.service_name = service_name
        self.logger = logging.getLogger(service_name)
        self.logger.setLevel(logging.INFO)

    def read_from_s3(self, bucket_base_name, key):
        """Read an object from S3 using the shared role's S3 permissions."""
        bucket = get_bucket_name(bucket_base_name)
        self.logger.info(f"Reading from S3: s3://{bucket}/{key}")
        try:
            response = get_s3_client().get_object(Bucket=bucket, Key=key)
            content = response['Body'].read().decode('utf-8')
            return json.loads(content)
        except get_s3_client().exceptions.NoSuchKey:
            self.logger.warning(f"Object not found: s3://{bucket}/{key}")
            return None
        except Exception as e:
            self.logger.error(f"S3 read error: {str(e)}")
            raise

    def write_to_s3(self, bucket_base_name, key, data):
        """Write an object to S3 using the shared role's S3 permissions."""
        bucket = get_bucket_name(bucket_base_name)
        self.logger.info(f"Writing to S3: s3://{bucket}/{key}")
        try:
            get_s3_client().put_object(
                Bucket=bucket,
                Key=key,
                Body=json.dumps(data, default=str),
                ContentType='application/json',
                ServerSideEncryption='aws:kms'
            )
            return True
        except Exception as e:
            self.logger.error(f"S3 write error: {str(e)}")
            raise

    def get_dynamodb_item(self, table_base_name, key):
        """Get an item from DynamoDB using the shared role's DynamoDB permissions."""
        table_name = get_table_name(table_base_name)
        self.logger.info(f"Getting item from DynamoDB: {table_name}")
        try:
            table = get_dynamodb_resource().Table(table_name)
            response = table.get_item(Key=key)
            return response.get('Item')
        except Exception as e:
            self.logger.error(f"DynamoDB get error: {str(e)}")
            raise

    def put_dynamodb_item(self, table_base_name, item):
        """Put an item into DynamoDB using the shared role's DynamoDB permissions."""
        table_name = get_table_name(table_base_name)
        self.logger.info(f"Putting item to DynamoDB: {table_name}")
        try:
            table = get_dynamodb_resource().Table(table_name)
            item['updated_at'] = datetime.utcnow().isoformat() + 'Z'
            item['service_name'] = self.service_name
            table.put_item(Item=item)
            return True
        except Exception as e:
            self.logger.error(f"DynamoDB put error: {str(e)}")
            raise

    def query_dynamodb(self, table_base_name, key_condition_expression, expression_values,
                       index_name=None, limit=None):
        """Query DynamoDB table or index using the shared role's DynamoDB permissions."""
        table_name = get_table_name(table_base_name)
        self.logger.info(f"Querying DynamoDB: {table_name}, index: {index_name}")
        try:
            table = get_dynamodb_resource().Table(table_name)
            query_params = {
                'KeyConditionExpression': key_condition_expression,
                'ExpressionAttributeValues': expression_values,
            }
            if index_name:
                query_params['IndexName'] = index_name
            if limit:
                query_params['Limit'] = limit

            response = table.query(**query_params)
            return response.get('Items', [])
        except Exception as e:
            self.logger.error(f"DynamoDB query error: {str(e)}")
            raise

    def publish_to_sns(self, topic_name, message, subject=None, message_attributes=None):
        """Publish a message to SNS using the shared role's SNS permissions."""
        topic_arn = get_topic_arn(topic_name)
        self.logger.info(f"Publishing to SNS topic: {topic_arn}")
        try:
            params = {
                'TopicArn': topic_arn,
                'Message': json.dumps(message, default=str) if isinstance(message, dict) else message,
            }
            if subject:
                params['Subject'] = subject
            if message_attributes:
                params['MessageAttributes'] = message_attributes

            response = get_sns_client().publish(**params)
            self.logger.info(f"SNS message published: {response['MessageId']}")
            return response['MessageId']
        except Exception as e:
            self.logger.error(f"SNS publish error: {str(e)}")
            raise

    def send_to_sqs(self, queue_name, message, delay_seconds=0, message_attributes=None):
        """Send a message to SQS using the shared role's SQS permissions."""
        self.logger.info(f"Sending message to SQS queue: {queue_name}")
        try:
            queue_url = get_queue_url(queue_name)
            params = {
                'QueueUrl': queue_url,
                'MessageBody': json.dumps(message, default=str) if isinstance(message, dict) else message,
                'DelaySeconds': delay_seconds,
            }
            if message_attributes:
                params['MessageAttributes'] = message_attributes

            response = get_sqs_client().send_message(**params)
            self.logger.info(f"SQS message sent: {response['MessageId']}")
            return response['MessageId']
        except Exception as e:
            self.logger.error(f"SQS send error: {str(e)}")
            raise

    def delete_from_sqs(self, queue_name, receipt_handle):
        """Delete a message from SQS using the shared role's SQS permissions."""
        self.logger.info(f"Deleting message from SQS queue: {queue_name}")
        try:
            queue_url = get_queue_url(queue_name)
            get_sqs_client().delete_message(
                QueueUrl=queue_url,
                ReceiptHandle=receipt_handle
            )
            return True
        except Exception as e:
            self.logger.error(f"SQS delete error: {str(e)}")
            raise


