class OrderProcessor(MicroserviceBase):
    """
    Order processing microservice Lambda function.
    Uses the shared IAM role for S3, DynamoDB, SNS, and SQS access.
    """

    def __init__(self):
        super().__init__('order-processor')

    def process_order(self, order_data):
        """Process an incoming order through the pipeline."""
        order_id = order_data.get('order_id')
        self.logger.info(f"Processing order: {order_id}")

        # 1. Store order in DynamoDB (uses shared role's dynamodb:PutItem)
        order_record = {
            'order_id': order_id,
            'customer_id': order_data.get('customer_id'),
            'items': order_data.get('items', []),
            'total_amount': str(order_data.get('total_amount', 0)),
            'status': 'PROCESSING',
            'created_at': datetime.utcnow().isoformat() + 'Z',
        }
        self.put_dynamodb_item('orders', order_record)

        # 2. Store order details in S3 (uses shared role's s3:PutObject)
        s3_key = f"orders/{datetime.utcnow().strftime('%Y/%m/%d')}/{order_id}.json"
        self.write_to_s3('order-data', s3_key, order_data)

        # 3. Notify downstream services via SNS (uses shared role's sns:Publish)
        self.publish_to_sns(
            'order-events',
            {
                'event_type': 'ORDER_CREATED',
                'order_id': order_id,
                'customer_id': order_data.get('customer_id'),
                'timestamp': datetime.utcnow().isoformat() + 'Z',
            },
            subject=f"New Order: {order_id}"
        )

        # 4. Queue for payment processing via SQS (uses shared role's sqs:SendMessage)
        self.send_to_sqs(
            'payment-processing',
            {
                'order_id': order_id,
                'amount': order_data.get('total_amount'),
                'customer_id': order_data.get('customer_id'),
                'payment_method': order_data.get('payment_method'),
            }
        )

        # 5. Queue for inventory check via SQS
        self.send_to_sqs(
            'inventory-check',
            {
                'order_id': order_id,
                'items': order_data.get('items', []),
            }
        )

        return {
            'order_id': order_id,
            'status': 'PROCESSING',
            'message': 'Order submitted successfully',
        }

    def get_order(self, order_id):
        """Retrieve order details."""
        # Uses shared role's dynamodb:GetItem permission
        item = self.get_dynamodb_item('orders', {'order_id': order_id})
        if not item:
            return None
        return item


# Initialize processor outside handler for Lambda container reuse
order_processor = OrderProcessor()


def lambda_handler(event, context):
    """
    Main Lambda handler for the Order Processor microservice.

    This function uses the shared IAM role that provides access to:
    - S3: Read/write order data to project-scoped buckets
    - DynamoDB: CRUD operations on project-scoped tables
    - SNS: Publish order events to project-scoped topics
    - SQS: Send messages to project-scoped queues
    - CloudWatch: Logging and custom metrics
    - SSM: Read shared configuration parameters

    Supports:
    - API Gateway events (POST/GET for orders)
    - SQS trigger events (batch processing)
    - SNS trigger events (event-driven processing)
    - Direct invocation
    """
    logger.info(f"Event received: {json.dumps(event, default=str)[:500]}")
    logger.info(f"Function: {context.function_name}, Request ID: {context.aws_request_id}")

    try:
        # Handle API Gateway events
        if 'httpMethod' in event:
            return _handle_api_gateway_event(event)

        # Handle SQS trigger events
        elif 'Records' in event and event['Records'][0].get('eventSource') == 'aws:sqs':
            return _handle_sqs_event(event)

        # Handle SNS trigger events
        elif 'Records' in event and event['Records'][0].get('EventSource') == 'aws:sns':
            return _handle_sns_event(event)

        # Handle direct invocation
        elif 'action' in event:
            return _handle_direct_invocation(event)

        else:
            logger.warning(f"Unrecognized event format")
            return ServiceResponse.error('Unrecognized event format', 400)

    except Exception as e:
        logger.error(f"Unhandled exception: {str(e)}", exc_info=True)
        return ServiceResponse.error(
            f"Internal server error: {str(e)}",
            500,
            'INTERNAL_ERROR'
        )


def _handle_api_gateway_event(event):
    """Handle HTTP requests from API Gateway."""
    http_method = event['httpMethod']
    path = event.get('path', '')
    body = json.loads(event.get('body', '{}')) if event.get('body') else {}
    path_params = event.get('pathParameters') or {}
    query_params = event.get('queryStringParameters') or {}

    if http_method == 'POST' and '/orders' in path:
        # Validate required fields
        required_fields = ['order_id', 'customer_id', 'items', 'total_amount']
        missing = [f for f in required_fields if f not in body]
        if missing:
            return ServiceResponse.error(
                f"Missing required fields: {', '.join(missing)}",
                400,
                'VALIDATION_ERROR'
            )
        result = order_processor.process_order(body)
        return ServiceResponse.success(result, 201)

    elif http_method == 'GET' and '/orders' in path:
        order_id = path_params.get('order_id') or query_params.get('order_id')
        if not order_id:
            return ServiceResponse.error('order_id is required', 400, 'VALIDATION_ERROR')
        result = order_processor.get_order(order_id)
        if not result:
            return ServiceResponse.error('Order not found', 404, 'NOT_FOUND')
        return ServiceResponse.success(result)

    else:
        return ServiceResponse.error('Method not allowed', 405, 'METHOD_NOT_ALLOWED')


def _handle_sqs_event(event):
    """Handle messages from SQS queue triggers."""
    processed = 0
    failed = 0

    for record in event.get('Records', []):
        try:
            message_body = json.loads(record['body'])
            logger.info(f"Processing SQS message: {record['messageId']}")

            # Process based on message content
            if 'order_update' in message_body:
                order_id = message_body['order_id']
                new_status = message_body['order_update']['status']
                order_processor.put_dynamodb_item('orders', {
                    'order_id': order_id,
                    'status': new_status,
                })

                # Notify about status change
                order_processor.publish_to_sns(
                    'order-events',
                    {
                        'event_type': 'ORDER_STATUS_CHANGED',
                        'order_id': order_id,
                        'new_status': new_status,
                        'timestamp': datetime.utcnow().isoformat() + 'Z',
                    }
                )

            processed += 1

        except Exception as e:
            logger.error(f"Failed to process SQS message {record['messageId']}: {str(e)}")
            failed += 1

    result = {
        'processed': processed,
        'failed': failed,
        'total': len(event.get('Records', []))
    }
    logger.info(f"SQS batch result: {json.dumps(result)}")
    return result


def _handle_sns_event(event):
    """Handle notifications from SNS topic triggers."""
    processed = 0

    for record in event.get('Records', []):
        try:
            sns_message = record['Sns']
            message_body = json.loads(sns_message['Message'])
            logger.info(f"Processing SNS notification: {sns_message['MessageId']}")

            event_type = message_body.get('event_type', '')

            if event_type == 'PAYMENT_COMPLETED':
                order_id = message_body['order_id']
                order_processor.put_dynamodb_item('orders', {
                    'order_id': order_id,
                    'status': 'PAID',
                    'payment_completed_at': datetime.utcnow().isoformat() + 'Z',
                })
                # Forward to fulfillment queue
                order_processor.send_to_sqs(
                    'order-fulfillment',
                    {
                        'order_id': order_id,
                        'action': 'SHIP',
                    }
                )

            elif event_type == 'PAYMENT_FAILED':
                order_id = message_body['order_id']
                order_processor.put_dynamodb_item('orders', {
                    'order_id': order_id,
                    'status': 'PAYMENT_FAILED',
                    'failure_reason': message_body.get('reason', 'Unknown'),
                })

            processed += 1

        except Exception as e:
            logger.error(f"Failed to process SNS message: {str(e)}")

    return {'processed': processed}


def _handle_direct_invocation(event):
    """Handle direct Lambda invocations."""
    action = event.get('action')

    if action == 'get_order':
        order_id = event.get('order_id')
        result = order_processor.get_order(order_id)
        return {'success': True, 'data': result}

    elif action == 'process_order':
        result = order_processor.process_order(event.get('order_data', {}))
        return {'success': True, 'data': result}

    elif action == 'health_check':
        return {
            'success': True,
            'service': 'order-processor',
            'environment': ENV,
            'status': 'healthy',
            'timestamp': datetime.utcnow().isoformat() + 'Z',
        }

    else:
        return {'success': False, 'error': f'Unknown action: {action}'}